import { Component, OnInit } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-candidate-internships',
  template: `
  <div class="page">
    <div class="page-header">
      <div>
        <h1 class="page-title">Available Internships</h1>
        <p class="muted">Explore and apply to internships</p>
      </div>
      <div>
        <button class="btn btn-ghost" (click)="router.navigate(['/candidate/dashboard'])">Back</button>
        <button class="btn btn-black" (click)="logout()">Logout</button>
      </div>
    </div>

    <div class="card-grid" style="margin-top:14px">
      <div *ngFor="let i of internships" class="card-item">
        <h3 style="text-align:center;color:var(--text)">{{i.companyName}}</h3>
        <h4 style="margin:6px 0">{{i.title}}</h4>
        <p class="muted" style="margin:6px 0">{{i.workLocation}} · {{i.ctc}}</p>
        <p style="margin-top:8px">{{i.description}}</p>
        <div class="card-actions" style="margin-top:10px">
          <button *ngIf="hasApplied(i.id)" class="btn btn-ghost" disabled>Applied</button>
          <button *ngIf="!hasApplied(i.id)" class="btn" (click)="selectInternship(i)">Apply</button>
        </div>
      </div>
    </div>

    <div *ngIf="selectedInternship" class="modal-form">
      <div class="card-item" style="max-width:700px;margin:auto">
        <h2>Apply for {{selectedInternship.title}} at {{selectedInternship.companyName}}</h2>
        <div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:8px">
          <input class="form-control" placeholder="Full Name" [(ngModel)]="candidateName" />
          <input class="form-control" placeholder="Phone" [(ngModel)]="phone" />
          <input class="form-control" placeholder="Degree" [(ngModel)]="degree" />
          <input class="form-control" placeholder="College" [(ngModel)]="college" />
          <input class="form-control" placeholder="CGPA" [(ngModel)]="cgpa" />
          <input class="form-control" placeholder="Skills (comma separated)" [(ngModel)]="skills" />
        </div>
        <div style="margin-top:10px">
          <input type="file" accept="application/pdf" (change)="onResumeSelected($event)" />
        </div>
        <div style="margin-top:12px">
          <button class="btn" (click)="handleApply()">Submit Application</button>
          <button class="btn btn-ghost" style="margin-left:8px" (click)="selectedInternship=null">Cancel</button>
        </div>
      </div>
    </div>
  </div>
  `
})
export class CandidateInternshipsComponent implements OnInit {
  internships: any[] = [];
  applications: any[] = [];
  selectedInternship: any = null;
  candidateName = '';
  phone = '';
  degree = '';
  college = '';
  cgpa = '';
  skills = '';
  resume: any = null;

  constructor(public auth: AuthService, private http: HttpClient, public router: Router) {}

  ngOnInit() {
    this.fetchInternships();
    this.fetchApplications();
  }

  logout() { this.auth.logout(); this.router.navigate(['/']); }

  async fetchInternships() {
    try { this.internships = await this.http.get<any[]>('http://localhost:8080/api/internships').toPromise(); } catch (err) { console.error(err); }
  }

  async fetchApplications() {
    try {
      const res: any = await this.http.get<any[]>('http://localhost:8080/api/applications').toPromise();
      this.applications = res.filter((a: any) => a.email === this.auth.user?.email);
    } catch (err) { console.error(err); }
  }

  hasApplied(internshipId: any) { return this.applications.some(app => app.internshipId === internshipId); }

  selectInternship(i: any) { this.selectedInternship = i; }

  onResumeSelected(e: any) { this.resume = e.target.files?.[0]; }

  async handleApply() {
    if (!this.resume) return alert('Please upload resume');
    const form = new FormData();
    form.append('internshipId', this.selectedInternship.id);
    form.append('candidateName', this.candidateName || '');
    form.append('email', this.auth.user?.email || '');
    form.append('phone', this.phone || '');
    form.append('degree', this.degree || '');
    form.append('college', this.college || '');
    form.append('cgpa', this.cgpa || '');
    form.append('skills', this.skills || '');
    form.append('resume', this.resume);
    try {
      await this.http.post('http://localhost:8080/api/applications/apply', form).toPromise();
      alert('Application submitted!');
      this.selectedInternship = null; this.fetchApplications();
      this.router.navigate(['/candidate/applied']);
    } catch (err) { console.error(err); alert('Error submitting application'); }
  }
}
